class Solution:
    def canMakeSubsequence(self, str1: str, str2: str) -> bool:
        i = 0  # Pointer for str1
        j = 0  # Pointer for str2
        n, m = len(str1), len(str2)

        while i < n and j < m:
            # Check if current character in str1 can be transformed to match str2[j]
            if ord(str1[i]) == ord(str2[j]):
                j += 1
                i += 1
            elif ord(str1[i]) + 1 == ord(str2[j]):
                j += 1
                i += 1
            elif ord(str1[i]) == ord('z') and ord(str2[j]) == ord('a'):
                j += 1
                i += 1
            else:
                i += 1

        return j == m
